+				auto functionInfo = irBuilder.CreateLoad(functionPointerPointer);  //offset of code
+				llvm::Value* running_code_start = irBuilder.CreateLoad(emitLiteralPointer((void*)(-18848), llvmI64Type->getPointerTo(256)));  ///XXX literal
